input.content:
.toolsSection {
  width: 100%;
  display: flex;
  justify-content: center;
  align-items: flex-start;
  padding-top: 28px;
  padding-bottom: 32px;
}

.toolsShell {
  position: relative;
  width: 100%;
  max-width: 940px;
}

.toolsGlow {
  position: absolute;
  inset: -28px;
  border-radius: 44px;
  background:
    radial-gradient(circle at 18% 18%, rgba(95, 134, 255, 0.2) 0%, transparent 34%),
    radial-gradient(circle at 82% 28%, rgba(255, 255, 255, 0.12) 0%, transparent 28%),
    radial-gradient(circle at 50% 100%, rgba(166, 136, 255, 0.16) 0%, transparent 40%);
  filter: blur(28px);
  opacity: 0.9;
  pointer-events: none;
}

.toolsCard {
  position: relative;
  overflow: hidden;
  padding: 32px;
  border-radius: 36px;
  background:
    linear-gradient(145deg, rgba(255, 255, 255, 0.12) 0%, rgba(255, 255, 255, 0.04) 24%, rgba(11, 13, 20, 0.82) 100%),
    linear-gradient(180deg, rgba(255, 255, 255, 0.04), rgba(255, 255, 255, 0.01));
  border: 1px solid rgba(255, 255, 255, 0.12);
  box-shadow:
    0 34px 100px rgba(0, 0, 0, 0.58),
    inset 0 1px 0 rgba(255, 255, 255, 0.18),
    inset 0 -1px 0 rgba(255, 255, 255, 0.04);
  backdrop-filter: blur(26px) saturate(140%);
  -webkit-backdrop-filter: blur(26px) saturate(140%);
}

.toolsHeader {
  position: relative;
  z-index: 1;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 16px;
}

.toolsKicker {
  margin: 0 0 10px;
  font-size: 12px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.52);
}

.toolsTitle {
  margin: 0;
  font-size: clamp(30px, 3.5vw, 44px);
  line-height: 1.04;
  letter-spacing: -0.04em;
  font-weight: 520;
  color: rgba(255, 255, 255, 0.96);
}

.toolsDescription {
  position: relative;
  z-index: 1;
  margin: 24px 0 28px;
  max-width: 700px;
  font-size: 17px;
  line-height: 1.7;
  color: rgba(246, 247, 248, 0.72);
}

.toolsForm {
  position: relative;
  z-index: 1;
}

.toolsLabel {
  display: inline-block;
  margin-bottom: 10px;
  font-size: 12px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.6);
}

.toolsInputRow {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 12px;
}

.toolsInput {
  min-height: 58px;
  padding: 0 18px;
  border-radius: 18px;
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(6, 8, 14, 0.78);
  color: rgba(246, 247, 248, 0.96);
  font-size: 16px;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease, background 0.2s ease;
}

.toolsInput::placeholder {
  color: rgba(246, 247, 248, 0.34);
}

.toolsInput:focus {
  border-color: rgba(137, 167, 255, 0.52);
  box-shadow: 0 0 0 4px rgba(95, 134, 255, 0.12);
  background: rgba(8, 10, 18, 0.9);
}

.toolsButton {
  min-height: 58px;
  padding: 0 22px;
  border-radius: 18px;
  border: 1px solid rgba(255, 255, 255, 0.14);
  background: linear-gradient(135deg, #89a7ff 0%, #5f86ff 100%);
  color: #08111f;
  font-size: 14px;
  font-weight: 700;
  letter-spacing: 0.02em;
  cursor: pointer;
  box-shadow:
    0 18px 40px rgba(95, 134, 255, 0.28),
    inset 0 1px 0 rgba(255, 255, 255, 0.4);
  transition: transform 0.16s ease, filter 0.2s ease, box-shadow 0.2s ease;
}

.toolsButton:hover:not(:disabled) {
  transform: translateY(-1px);
  filter: brightness(1.03);
  box-shadow:
    0 22px 48px rgba(95, 134, 255, 0.34),
    inset 0 1px 0 rgba(255, 255, 255, 0.4);
}

.toolsButton:disabled {
  cursor: wait;
  opacity: 0.72;
}

.toolsError {
  margin: 12px 0 0;
  color: #ff9b9b;
  font-size: 14px;
}

.profilePanel {
  position: relative;
  z-index: 1;
  margin-top: 24px;
  padding: 24px;
  border-radius: 28px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.045) 0%, rgba(255, 255, 255, 0.02) 100%);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.08);
}

.profileHeader {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 16px;
}

.profileEyebrow {
  margin: 0 0 8px;
  font-size: 11px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.46);
}

.profileCompany {
  margin: 0;
  font-size: 26px;
  line-height: 1.1;
  letter-spacing: -0.03em;
  color: rgba(255, 255, 255, 0.96);
}

.profileAddress {
  flex-shrink: 0;
  padding: 10px 14px;
  border-radius: 999px;
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(255, 255, 255, 0.05);
  color: rgba(246, 247, 248, 0.8);
  font-size: 12px;
}

.profileSummary {
  margin: 20px 0 0;
  font-size: 16px;
  line-height: 1.7;
  color: rgba(246, 247, 248, 0.74);
}

.profileScores {
  margin-top: 22px;
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 12px;
}

.profileScoreCard {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 18px;
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(255, 255, 255, 0.04);
}

.profileScoreLabel {
  font-size: 11px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.46);
}

.profileScoreValue {
  font-size: 22px;
  line-height: 1.1;
  letter-spacing: -0.03em;
  color: rgba(255, 255, 255, 0.94);
}

.profileColumns {
  margin-top: 18px;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.profileListCard {
  padding: 18px;
  border-radius: 20px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(255, 255, 255, 0.03);
}

.profileListLabel {
  display: inline-block;
  margin-bottom: 12px;
  font-size: 11px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.48);
}

.profileList {
  margin: 0;
  padding-left: 18px;
  display: grid;
  gap: 10px;
  color: rgba(246, 247, 248, 0.82);
  line-height: 1.6;
}

.profileEmpty {
  min-height: 240px;
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 12px;
  color: rgba(246, 247, 248, 0.68);
}

.profileEmptyLabel {
  font-size: 11px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(246, 247, 248, 0.44);
}

